// Perturbed tables (match the perturbed typed-body attrs): grid[5] low byte +1,
// ksigns[5] 5 -> 200.
static uint32_t iq3xxs_grid_pert[256];
static uint8_t ksigns_pert[128];

static inline float fp16_to_fp32(uint16_t h) {
  _Float16 hf; std::memcpy(&hf, &h, sizeof(uint16_t)); return (float)hf;
}

// The two compiler-emitted kernels (real-attr + perturbed-attr; distinct symbols).
extern "C" void
tcrv_emitc_ggml_vec_dot_iq3_xxs_q8_K_kernel_ggml_vec_dot_iq3_xxs_q8_K(
    size_t n, float *s, const uint8_t *vx, const uint8_t *vy);
extern "C" void
tcrv_emitc_ggml_vec_dot_iq3_xxs_q8_K_PERT_kernel_ggml_vec_dot_iq3_xxs_q8_K_PERT(
    size_t n, float *s, const uint8_t *vx, const uint8_t *vy);

static void ggml_generic_param(int n, float *s, const void *vx, const void *vy,
                               const uint32_t *grid_tab, const uint8_t *ksign_tab) {
  const block_iq3_xxs *x = (const block_iq3_xxs *)vx;
  const block_q8_K *y = (const block_q8_K *)vy;
  const int nb = n / QK_K;
  uint32_t aux32;
  float sumf = 0.f;
  for (int i = 0; i < nb; ++i) {
    const float d = fp16_to_fp32(x[i].d) * y[i].d;
    const uint8_t *q3 = x[i].qs;
    const uint8_t *gas = x[i].qs + QK_K / 4;
    const int8_t *q8 = y[i].qs;
    int32_t bsum = 0;
    for (int ib32 = 0; ib32 < QK_K / 32; ++ib32) {
      std::memcpy(&aux32, gas, sizeof(uint32_t)); gas += sizeof(uint32_t);
      const uint32_t ls = 2 * (aux32 >> 28) + 1;
      int32_t sumi = 0;
      for (int l = 0; l < 4; ++l) {
        const uint8_t *grid1 = (const uint8_t *)(grid_tab + q3[2 * l + 0]);
        const uint8_t *grid2 = (const uint8_t *)(grid_tab + q3[2 * l + 1]);
        const uint8_t signs = ksign_tab[(aux32 >> 7 * l) & 127];
        for (int j = 0; j < 4; ++j) {
          sumi += grid1[j] * q8[j + 0] * (signs & kmask_iq2xs[j + 0] ? -1 : 1);
          sumi += grid2[j] * q8[j + 4] * (signs & kmask_iq2xs[j + 4] ? -1 : 1);
        }
        q8 += 8;
      }
      q3 += 8;
      bsum += sumi * ls;
    }
    sumf += d * bsum;
  }
  *s = 0.25f * sumf;
}

int main() {
  // Build the perturbed tables.
  for (int i = 0; i < 256; ++i) iq3xxs_grid_pert[i] = iq3xxs_grid[i];
  {
    uint32_t g = iq3xxs_grid[5];
    iq3xxs_grid_pert[5] = (g & ~0xffu) | ((g + 1) & 0xffu);  // low byte +1
  }
  for (int i = 0; i < 128; ++i) ksigns_pert[i] = ksigns_iq2xs[i];
  ksigns_pert[5] = 200;

  // One super-block whose grid indices are all 5 and whose sign selectors are all 5,
  // so the perturbed grid[5] + ksigns[5] are EXERCISED.
  int nb = 1;
  uint8_t *xbuf = (uint8_t *)std::calloc(nb, IQ3XXS_STRIDE);
  uint8_t *ybuf = (uint8_t *)std::calloc(nb, Q8K_STRIDE);
  block_iq3_xxs *x = (block_iq3_xxs *)xbuf;
  block_q8_K *y = (block_q8_K *)ybuf;
  float dx = 0.5f; _Float16 hx = (_Float16)dx; std::memcpy(&x->d, &hx, 2);
  for (int k = 0; k < 64; ++k) x->qs[k] = 5;          // every grid index = 5
  uint8_t *gas = x->qs + QK_K / 4;
  for (int ib32 = 0; ib32 < 8; ++ib32) {
    uint32_t signsel = 5;                              // every sign selector = 5
    uint32_t aux = signsel | (signsel << 7) | (signsel << 14) | (signsel << 21);
    aux = (aux & 0x0fffffffu) | (3u << 28);            // a mid scale
    std::memcpy(gas + ib32 * 4, &aux, sizeof(uint32_t));
  }
  y->d = 1.0f;
  // A non-degenerate q8 pattern so the real-attr dot is clearly non-zero (avoids the
  // sign-cancellation that an all-equal q8 would produce against grid index 5's signs).
  for (int k = 0; k < QK_K; ++k) y->qs[k] = (int8_t)(3 + (k % 5));

  int n = nb * QK_K;
  float s_real_hw = 0.f, s_pert_hw = 0.f, s_real_ref = 0.f, s_pert_ref = 0.f;
  tcrv_emitc_ggml_vec_dot_iq3_xxs_q8_K_kernel_ggml_vec_dot_iq3_xxs_q8_K(
      (size_t)n, &s_real_hw, xbuf, ybuf);
  tcrv_emitc_ggml_vec_dot_iq3_xxs_q8_K_PERT_kernel_ggml_vec_dot_iq3_xxs_q8_K_PERT(
      (size_t)n, &s_pert_hw, xbuf, ybuf);
  ggml_generic_param(n, &s_real_ref, xbuf, ybuf, iq3xxs_grid, ksigns_iq2xs);
  ggml_generic_param(n, &s_pert_ref, xbuf, ybuf, iq3xxs_grid_pert, ksigns_pert);

  std::printf("KNOB real-attr kernel:  HW=%.6f  ref(real-table)=%.6f  %s\n",
              s_real_hw, s_real_ref,
              s_real_hw == s_real_ref ? "MATCH" : "MISMATCH");
  std::printf("KNOB pert-attr kernel:  HW=%.6f  ref(pert-table)=%.6f  %s\n",
              s_pert_hw, s_pert_ref,
              s_pert_hw == s_pert_ref ? "MATCH" : "MISMATCH");
  int diverge = (s_real_hw != s_pert_hw);
  std::printf("KNOB real-HW vs pert-HW: %.6f vs %.6f -> %s\n", s_real_hw, s_pert_hw,
              diverge ? "DIVERGE (PASS: attr is the live knob)" : "SAME (FAIL!)");
  int ok = (s_real_hw == s_real_ref) && (s_pert_hw == s_pert_ref) && diverge;
  std::printf("KNOB RESULT: %s\n", ok ? "ALL PASS" : "FAIL");
  std::free(xbuf); std::free(ybuf);
  return ok ? 0 : 1;
}
